import numpy as np

def run_practice():
    prior = np.array([np.log(0.5), np.log(0.5)])
    likelihood = {'good': np.array([np.log(0.8), np.log(0.2)]), 'bad': np.array([np.log(0.1), np.log(0.9)])}
    scores = prior + likelihood['good'] + likelihood['bad']
    expected = np.array([np.log(0.5*0.8*0.1), np.log(0.5*0.2*0.9)])
    assert np.allclose(scores, expected)
    print('[PASS] Naive Bayes likelihood manual calculation passes.')

if __name__ == '__main__':
    run_practice()
